def _make_response(payload_hex: str, *, msg_type: int, raw: bytes = b"raw") -> ResponseFrame:
    payload = bytes.fromhex(payload_hex)
    return ResponseFrame(
        control=0x1C,
        msg_id=3,
        msg_type=msg_type,
        zip_length=len(payload),
        length=len(payload),
        data=payload,
        raw=raw,
    )


def test_parse_history_minute_payload() -> None:
    response = _make_response(PAYLOAD_HEX, msg_type=0x0FB4, raw=b"frame")

    parsed = parse_history_minute_payload("20260306", response, include_raw=True)

    assert parsed.count == 240
    assert parsed.trading_date.isoformat() == "2026-03-06"
    assert parsed.items[0].time.strftime("%H:%M") == "09:31"
    assert parsed.items[0].price_milli == 10820
    assert parsed.items[0].volume == 16557
    assert parsed.items[119].time.strftime("%H:%M") == "11:30"
    assert parsed.items[120].time.strftime("%H:%M") == "13:01"
    assert parsed.items[-1].time.strftime("%H:%M") == "15:00"
    assert parsed.items[-1].price_milli == 10820
    assert parsed.items[-1].volume == 6768
    assert parsed.raw_payload_hex == PAYLOAD_HEX


def test_parse_live_minute_payload_sz_sample() -> None:
    response = _make_response(LIVE_PAYLOAD_HEX_SZ, msg_type=0x051D)

    parsed = parse_minute_payload(response, trading_date="2026-03-07", include_raw=True)

    assert parsed.count == 240
    assert parsed.trading_date.isoformat() == "2026-03-07"
    assert parsed.items[0].time.strftime("%H:%M") == "09:31"
    assert parsed.items[0].price_milli == 10820
    assert parsed.items[0].volume == 16557
    assert parsed.items[1].price_milli == 10810
    assert parsed.items[1].volume == 9800
    assert parsed.items[119].time.strftime("%H:%M") == "11:30"
    assert parsed.items[120].time.strftime("%H:%M") == "13:01"
    assert parsed.items[-1].time.strftime("%H:%M") == "15:00"
    assert parsed.items[-1].price_milli == 10820
    assert parsed.items[-1].volume == 6768
    assert parsed.raw_payload_hex == LIVE_PAYLOAD_HEX_SZ


def test_parse_live_minute_payload_sh_sample() -> None:
    response = _make_response(LIVE_PAYLOAD_HEX_SH, msg_type=0x051D)

    parsed = parse_minute_payload(response, trading_date="2026-03-07", include_raw=True)

    assert parsed.count == 240
    assert parsed.trading_date.isoformat() == "2026-03-07"
    assert parsed.items[0].time.strftime("%H:%M") == "09:31"
    assert parsed.items[0].price_milli == 9810
    assert parsed.items[0].volume == 13417
    assert parsed.items[1].price_milli == 9810
    assert parsed.items[1].volume == 9445
    assert parsed.items[-1].time.strftime("%H:%M") == "15:00"
    assert parsed.items[-1].price_milli == 9890
    assert parsed.items[-1].volume == 6827
    assert parsed.raw_payload_hex == LIVE_PAYLOAD_HEX_SH


def test_get_minute_without_date_uses_live_minute_request() -> None:
    client = TdxClient()
    client.connect = Mock()

    connection = Mock()
    connection.request_minute.return_value = "live"
    client._connections = [connection]

    assert client.get_minute("sz000001") == "live"
    client.connect.assert_called_once_with()
    connection.request_minute.assert_called_once_with("sz000001", include_raw=False)
    connection.request_history_minute.assert_not_called()


def test_get_minute_with_date_uses_history_minute_request() -> None:
    client = TdxClient()
    client.connect = Mock()

    connection = Mock()
    connection.request_history_minute.return_value = "history"
    client._connections = [connection]

    assert client.get_minute("sz000001", "2026-03-06") == "history"
    client.connect.assert_called_once_with()
    connection.request_history_minute.assert_called_once_with("sz000001", "2026-03-06", include_raw=False)
    connection.request_minute.assert_not_called()


def test_normalize_trading_date() -> None:
    text, trading_day = normalize_trading_date("2026-03-06")
    assert text == "20260306"
    assert trading_day == date(2026, 3, 6)

    text2, trading_day2 = normalize_trading_date(date(2026, 3, 6))
    assert text2 == "20260306"
    assert trading_day2 == date(2026, 3, 6)

    text3, trading_day3 = normalize_trading_date(datetime(2026, 3, 6, 15, 0, tzinfo=SHANGHAI_TZ))
    assert text3 == "20260306"
    assert trading_day3 == date(2026, 3, 6)


def test_minute_index_to_datetime() -> None:
    assert minute_index_to_datetime("20260306", 0).strftime("%H:%M") == "09:31"
    assert minute_index_to_datetime("20260306", 119).strftime("%H:%M") == "11:30"
    assert minute_index_to_datetime("20260306", 120).strftime("%H:%M") == "13:01"
    assert minute_index_to_datetime("20260306", 239).strftime("%H:%M") == "15:00"
